using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn fundamental programming concepts using C#. Topics include variables, control flow, methods, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design and analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published over 40 papers in top-tier conferences.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Code = "CS301", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for 10 years before joining academia. She specializes in distributed databases.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Code = "CS401", Title = "Machine Learning", Description = "Foundations of machine learning including supervised learning, unsupervised learning, and neural networks.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 5, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator who has taught calculus for over 20 years.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 6, Code = "MATH201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra and numerical methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Code = "MATH301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator who has taught calculus for over 20 years.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 8, Code = "ENG101", Title = "Composition & Rhetoric", Description = "Develop effective writing skills through essays, research papers, and rhetorical analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. David Miller", InstructorBio = "Prof. Miller is a published author and has taught writing at the university level for 12 years.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Code = "ENG201", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", InstructorName = "Dr. Lisa Johnson", InstructorBio = "Dr. Johnson specializes in 20th-century American fiction and has authored three books on the subject.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 10, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 3:00–5:00 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a former NASA researcher with expertise in classical mechanics and astrophysics.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 11, Code = "PHYS201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM + Fri Lab 2:00–4:00 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a former NASA researcher with expertise in classical mechanics and astrophysics.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 12, Code = "HIST101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistoric times through the Renaissance.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen is a specialist in ancient civilizations with extensive fieldwork experience.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 13, Code = "HIST201", Title = "Modern World History", Description = "Major political, social, and economic developments from 1500 to the present.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen is a specialist in ancient civilizations with extensive fieldwork experience.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Code.ToLowerInvariant().Contains(term) ||
                c.Title.ToLowerInvariant().Contains(term) ||
                c.InstructorName.ToLowerInvariant().Contains(term));
        }

        return query.ToList();
    }
}

