@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<div class="container mt-4">
    <h1 class="mb-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by code, title, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" @onkeyup="ApplyFilters" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId" @bind:after="ApplyFilters">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
    else
    {
        <p class="text-muted mb-3">Showing @filteredCourses.Count course(s)</p>
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in filteredCourses)
                    {
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? departmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> filteredCourses = new();
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        selectedDepartmentId = departmentId ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(searchTerm, selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="container mt-4">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@model.FullName</strong>. Your enrollment request for
                <strong>@selectedCourseTitle</strong> has been received.</p>
            <p>You will receive a confirmation via your university email within 2 business days.</p>
            <hr>
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
            <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another Request</button>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="alert alert-danger" />

                    <div class="mb-3">
                        <label for="fullName" class="form-label">Full Name</label>
                        <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
                        <ValidationMessage For="() => model.FullName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g., AB123456" />
                        <ValidationMessage For="() => model.StudentId" class="text-danger" />
                        <div class="form-text">Format: 2 uppercase letters followed by 6 digits (e.g., AB123456)</div>
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                            <option value="0">— Select a course —</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => model.CourseId" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                    <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </EditForm>
            </div>

            <div class="col-md-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5 class="card-title">Information</h5>
                        <ul class="mb-0">
                            <li>Enrollment requests are processed within 2 business days.</li>
                            <li>You will receive confirmation at your university email address.</li>
                            <li>Contact the registrar's office for questions.</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? courseId { get; set; }

    private EnrollmentRequest model = new();
    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (courseId.HasValue)
        {
            model.CourseId = courseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        submitted = true;
    }

    private void Reset()
    {
        model = new EnrollmentRequest();
        submitted = false;
    }
}

